insert into public.content_entries (type, slug, title, status, locale, payload, seo)
values
  ('proof_card', 'ddc-rust-test', '20-year rust and scale, cleared in 30 minutes', 'published', 'en', '{"eyebrow":"HVAC / Water","kind":"hvac","chips":["VertKleen HCR","Displaced CLR"],"source":"Source: DDC Engineering rust test","image":"img/proof/cases/ddc-rust.webp?v=20260617b","image_alt":"Rusted HVAC component cleared with VertKleen HCR","result":"CLR ran for 36 hours and failed. VertKleen HCR cleared the same rust and scale in half an hour, verified by DDC Engineering (David DaSilva, PE).","sort_order":1,"image_w":1200,"image_h":579}'::jsonb, '{}'::jsonb),
  ('proof_card', 'brewery-cip-trials', 'Full CR + HCR CIP at seven Florida breweries', 'published', 'en', '{"eyebrow":"Food & Beverage","kind":"food","chips":["VertKleen CR + HCR","Displaced caustic + acid"],"source":"Source: brewery trials, incl. HellnBlazes (endorser)","image":"img/proof/cases/brewery.webp?v=20260617b","image_alt":"Brewery tank and heat exchanger cleaned with VertKleen CR and HCR","result":"CR alkaline wash then HCR acid wash matched or beat caustic soda plus acid blends at equal concentration and CIP time. Final sanitation requirements remain label- and site-protocol dependent.","sort_order":2,"image_w":1200,"image_h":900,"href":"docs/brewery-cip-trial-brewlando.pdf"}'::jsonb, '{}'::jsonb),
  ('proof_card', 'walmart-dc-crhd', 'Simple Green replaced across Walmart DCs', 'published', 'en', '{"eyebrow":"Distribution / Cold Chain","kind":"distribution","chips":["VertKleen CRHD","Displaced Simple Green"],"source":"Source: Walmart DSC program","image":"img/proof/walmart-dc-proof-enhanced.webp?v=20260617b","image_alt":"Crown lift equipment in the Walmart distribution center cleaning program","result":"CRHD at about 50% active replaced Simple Green and Calci-Solve for heavy degreasing, saving an estimated $10k+ per year at one center. Crown and Plug Power supporting documents are available on request.","sort_order":3,"image_w":708,"image_h":513,"href":"docs/walmart-dc-brochure.pdf"}'::jsonb, '{}'::jsonb),
  ('proof_card', 'walmart-refrigeration-results', 'Refrigeration descaling in one maintenance window', 'published', 'en', '{"eyebrow":"Distribution / Refrigeration","kind":"distribution","chips":["VertKleen Descaler","Cold-chain systems"],"source":"Source: Walmart refrigeration case study","image":"img/proof/cases/walmart-refrigeration-results.webp","image_alt":"Walmart refrigeration descaling results table for VertKleen Descaler","result":"Walmart refrigeration material reports Descaler protocols across ammonia condenser circuits, warm-water heating, aluminum coils, copper bundles, and heat exchangers, with 4-8 hour descale windows by system.","sort_order":4,"image_w":1600,"image_h":1200,"href":"docs/walmart-refrigeration-case-study.pdf"}'::jsonb, '{}'::jsonb),
  ('proof_card', 'trinidad-tank-cleaning', 'Bunker-fuel tank cleaning test', 'published', 'en', '{"eyebrow":"Industrial Tank Cleaning","kind":"industrial","chips":["VertKleen CR + HCR","Bunker fuel residue"],"source":"Source: Trinidad tank cleaning test","image":"img/proof/cases/trinidad-tank-cr.webp","image_alt":"Bunker-fuel tank side before and after cleaning with VertKleen CR","result":"Trinidad test notes say CR removed oil residue with less product than a butoxyethanol comparator. The same report cautions that formal test procedure and environmental review should be written before scaling the method.","sort_order":5,"image_w":1600,"image_h":1200,"href":"docs/trinidad-tank-cleaning-test.pdf"}'::jsonb, '{}'::jsonb),
  ('proof_card', 'yellowfin-torque-wash', '43-foot Yellowfin washed and waxed dockside', 'published', 'en', '{"eyebrow":"Marine","kind":"marine","chips":["VertKleen Torque"],"source":"Source: Yellowfin vessel wash","image":"img/proof/cases/marine.webp?v=20260617b","image_alt":"43-foot Yellowfin vessel washed and waxed with VertKleen Torque","result":"VertKleen Torque cleaned and protected the hull and topsides in one step, within OEM finish-care requirements, with no harsh fumes around the water.","sort_order":6,"image_w":1175,"image_h":1125}'::jsonb, '{}'::jsonb),
  ('proof_card', 'uf-shands-drone-wash', 'Occupied campus cleaned by drone at UF Shands', 'published', 'en', '{"eyebrow":"Drone & Pressure Wash","kind":"facility","chips":["VertKleen MultiWash"],"source":"Source: UF Shands drone wash","image":"img/proof/cases/drone-before.webp?v=20260617b","image_alt":"Dirty UF Shands campus rooftops before VertKleen drone wash","result":"Clean Team USA used VertKleen MultiWash with an Apellix pressure-washing drone to clear years of scale and algae from trim, caulking, and glass, with the hospital occupied.","sort_order":7,"image_w":1200,"image_h":803}'::jsonb, '{}'::jsonb),
  ('proof_card', 'neatfreaks-hood-degrease', 'Restaurant hood filters and floors degreased', 'published', 'en', '{"eyebrow":"Food Service","kind":"food","chips":["VertKleen CR + CRHD","Displaced caustic degreasers"],"source":"Source: NeatFreaks application reports","image":"img/proof/cases/hood-before.webp?v=20260617b","image_alt":"Greasy commercial kitchen hood filters before cleaning","result":"NeatFreaks crews ran VertKleen across Boca Raton restaurants. About 32 oz of CRHD mopped 2,500 square feet, replacing caustic and solvent degreasers.","sort_order":8,"image_w":520,"image_h":650}'::jsonb, '{}'::jsonb),
  ('proof_card', 'fire-pump-descaler', 'Fire-pump solenoid and cavity descaled', 'published', 'en', '{"eyebrow":"Facilities / Fire","kind":"facility","chips":["VertKleen Descaler","Displaced acid washing"],"source":"Source: fire-protection maintenance","image":"img/proof/cases/fire-pump.webp?v=20260617b","image_alt":"Fire-pump component descaled with VertKleen Descaler","result":"VertKleen Descaler cleared scale from a fire-protection pump without acid washing, on a Siemens maintenance program, with no aggressive corrosion to the assembly.","sort_order":9,"image_w":681,"image_h":681}'::jsonb, '{}'::jsonb),
  ('proof_card', 'residential-ac-coil', 'AC coil cleaned, lower monthly bill', 'published', 'en', '{"eyebrow":"Residential / HVAC","kind":"hvac","chips":["VertKleen Descaler"],"source":"Source: residential AC coil report","image":"img/proof/cases/ac-coil.webp?v=20260617b","image_alt":"Residential AC coil cleaned with VertKleen Descaler","result":"A residential AC coil was cleaned and preserved with VertKleen Descaler, aluminum-fin compatible, reportedly cutting about $75 per month off the cooling bill.","sort_order":10,"image_w":839,"image_h":471}'::jsonb, '{}'::jsonb),
  ('proof_card', 'airboat-alumibrite', 'Commercial tourist airboat aluminum restored', 'published', 'en', '{"eyebrow":"Marine / Aluminum","kind":"marine","chips":["AlumiBrite + Torque","Displaced HF / HCl"],"source":"Source: airboat application","image":"img/proof/cases/airboat-before.webp?v=20260617b","image_alt":"Oxidized diamond-plate airboat aluminum before restoration","result":"AlumiBrite and Torque restored the hull and aluminum on a working tourist airboat, without the hydrofluoric or hydrochloric acid standard brighteners rely on.","sort_order":11,"image_w":682,"image_h":619}'::jsonb, '{}'::jsonb),
  ('proof_card', 'brevard-farm-hvac', 'Farm HVAC rust removed, one application', 'published', 'en', '{"eyebrow":"Agriculture / HVAC","kind":"hvac","chips":["VertKleen HCR","Displaced HCl handling"],"source":"Source: Brevard County farm HVAC","image":"img/proof/cases/farm-rust-before.webp?v=20260617b","image_alt":"Rust and scale on Brevard County farm diamond-plate before cleaning","result":"VertKleen HCR cleared heavy rust and scale on Brevard County farm HVAC and diamond-plated stainless without hydrochloric acid handling and with no pitting of the metal.","sort_order":12,"image_w":1057,"image_h":844}'::jsonb, '{}'::jsonb),
  ('proof_card', 'property-grout-moss', 'Grout, grime, moss, and algae cleared', 'published', 'en', '{"eyebrow":"Property","kind":"facility","chips":["VertKleen CR + LAM3"],"source":"Source: property maintenance applications","image":"img/proof/cases/grout-before.webp?v=20260617b","image_alt":"Grime and biological growth in tile grout before cleaning","result":"CR and LAM3 cleared biological growth and grime from grout, concrete, tile, and exterior surfaces without harsh acid or solvent cleaning.","sort_order":13,"image_w":934,"image_h":700}'::jsonb, '{}'::jsonb),
  ('proof_card', 'commercial-kitchen-crhd', 'Commercial kitchen deep-degreased', 'published', 'en', '{"eyebrow":"Food Service","kind":"food","chips":["VertKleen CRHD"],"source":"Source: commercial kitchen cleaning","image":"img/proof/cases/kitchen-before.webp?v=20260617b","image_alt":"Grease buildup on commercial kitchen equipment before cleaning","result":"CRHD cut baked-on grease from commercial kitchen equipment at high dilution, low-foam for easier rinse, without solvent or butyl odor in the space.","sort_order":14,"image_w":917,"image_h":852}'::jsonb, '{}'::jsonb)
